import './PopoverHelperContent.scss';

import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import React, { forwardRef, useMemo } from 'react';

import type { PopoverHelperContentProps } from './PopoverHelperContent.types';

export const PopoverHelperContent = forwardRef<HTMLDivElement, PopoverHelperContentProps>(
	({ title, body, className }, ref) => {
		const titleValue = useMemo(() => {
			if (!title) {
				return null;
			}

			return typeof title === 'string' ? (
				<Typography className="dsb_helper-title" variant="h5">
					{title}
				</Typography>
			) : (
				<div className="dsb_helper-title">{title}</div>
			);
		}, [title]);

		const bodyValue = useMemo(
			() =>
				typeof body === 'string' ? (
					<Typography className="dsb_helper-body" variant="caption">
						{body}
					</Typography>
				) : (
					<div className="dsb_helper-body">{body}</div>
				),
			[body],
		);

		return (
			<div ref={ref} className={classNames('dsb_helper', className)}>
				{titleValue}
				{bodyValue}
			</div>
		);
	},
);
